export function buscarCBO(termo: string): CBO[] {
  if (!termo || termo.length < 2) return []
  const t = termo.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '')
  return CBO_DATA.filter(c => {
    const nome = c.nome.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '')
    const cod  = c.codigo.replace(/\D/g,'')
    return nome.includes(t) || cod.includes(t)
  }).slice(0, 10)
}

// Retorna o melhor CBO para uma função/cargo — sempre retorna algo se houver qualquer correspondência
export function melhorCBO(funcao: string): CBO | null {
  if (!funcao || funcao.length < 2) return null
  const norm = (s: string) => s.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').trim()
  const t = norm(funcao)
  const palavras = t.split(/\s+/).filter(w => w.length > 3)

  let best: CBO | null = null
  let bestScore = 0

  for (const c of CBO_DATA) {
    const nome = norm(c.nome)
    let score = 0

    if (nome === t)              score = 100  // correspondência exata
    else if (nome.startsWith(t)) score = 85   // nome começa com o termo
    else if (t.startsWith(nome)) score = 75   // termo começa com o nome (nome mais curto)
    else if (nome.includes(t))   score = 65   // nome contém o termo
    else if (t.includes(nome))   score = 55   // termo contém o nome
    else if (palavras.length > 0) {
      // correspondência por palavras significativas
      const acertos = palavras.filter(w => nome.includes(w)).length
      if (acertos > 0) score = acertos * 25
    }

    if (score > bestScore) { bestScore = score; best = c }
  }

  return best
}
